module top_module(bcd_in, segments_out, invert);output reg	[6:0] segments_out;
    input		[3:0] bcd_in;
	input		invert;












	reg [6:0] decoded_segments;

	always @*
      case (bcd_in)

          4'b0001 : decoded_segments = 7'b1111001;   
          4'b0010 : decoded_segments = 7'b0100100;   
          4'b0011 : decoded_segments = 7'b0110000;   
          4'b0100 : decoded_segments = 7'b0011001;   
          4'b0101 : decoded_segments = 7'b0010010;   
          4'b0110 : decoded_segments = 7'b0000010;   
          4'b0111 : decoded_segments = 7'b1111000;   
          4'b1000 : decoded_segments = 7'b0000000;   
          4'b1001 : decoded_segments = 7'b0010000;   
          4'b1010 : decoded_segments = 7'b0001000;   
          4'b1011 : decoded_segments = 7'b0000011;   
          4'b1100 : decoded_segments = 7'b1000110;   
          4'b1101 : decoded_segments = 7'b0100001;   
          4'b1110 : decoded_segments = 7'b0000110;   
          4'b1111 : decoded_segments = 7'b0001110;   
          default : decoded_segments = 7'b1000000;   
      endcase

	always @*
		case (invert)
			1'b1 : segments_out = decoded_segments; 
			1'b0 : segments_out = ~decoded_segments; 
		endcase

endmodule
